VALUES
  ('social-worker-moex-03310', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會工作價值體系，下列敘述何者正確？①社會工作專業價值具有相當的持久性與穩定性', '["自由、尊嚴、正義是社會工作專業信奉的工具性價值", "案主自決與保密等是社會工作專業強 調的終極性價值", "社工人員的個人價值與社會工作的專業價值未必具一致性", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03311', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '服務對象長期受到嚴重肢體暴力而死亡，結果發現社會工作者接獲通報派案後，並未依規定前往 訪視，而僅用電話聯繫。事後卻說成是為了要幫服務對象保密。依據Bandura（1986）的道德解離 （moraldisengagement）的理論，上述情形屬於何種行為反應？', '["非人性化", "責任移轉", "掩過飾非", "道德辯證"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03312', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何種倫理理論被批評「只重視行為規則，而排除道德生活中的其他要素」？', '["品德論", "義務論", "關懷倫理", "情境倫理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03313', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某社福機構主管服膺規範倫理學中的義務論，下列何者符合此主管的想法？', '["社會工作者不可以修改服務對象的薪資紀錄，以符合低收入的資格", "社會工作者可以違反機構規定，以提供更好的服務", "只要企業有慈善公益捐贈，其他不法行為可以通融", "非營利組織為了提供更多服務，可以要求社會工作者回捐"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03314', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作的價值內涵中，有關處理人的方式的價值取向，社會工作專業認為幫助個人自我實現 是最重要的，不僅要促使個人的自我實現，也要尊重個人的自我決定。下列實務中，何者最接近 此種價值取向？', '["協助弱勢者找出每個人獨特能力與意向（intention）", "在夫妻爭取監護權的社區家事商談中，努力促成夫妻爭吵最小化", "在少年輔導個案身上，允許個人愛怎麼做，就怎麼做", "在社區理事會議爭議中，努力理解居民的共通性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03315', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當一名獨居行動越來越不方便的老人近來跌倒二次，你判斷轉介到安養機構照顧會比較妥適，但 是老人想繼續待在自家環境住所。依據Lowenberg和Dolgoff（1992；2000）的社會工作倫理抉擇 優先順序，你在轉介與否的選擇判斷上，應優先引用下列何種原則來考量？', '["最小傷害原則", "多元文化原則", "差別平等原則", "自主自由原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03316', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '負責分配救濟物資的社會工作者，常碰到社區中從事資源回收的個案，說自己年紀大了、身體不 好，而且競爭不過年輕人為理由來索取物資，但卻將剩餘物資轉送他人。當社會工作者知道這件 事後，在下次個案來機構索取物資時，就大聲質詢個案，並說個案是個騙子、假好心。個案可以 告社會工作者下列何種罪名？', '["業務過失罪", "公然侮辱罪", "洩漏機密罪", "洩漏個人資料罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03317', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Reamer於1990年提出的倫理兩難抉擇，下列敘述何者正確？①防止傷害到人類的行為必要前提', '["其他人的自我決定權優先於個人基本福祉的權利", "自身的基本福祉 優先於個人自我決定的權力", "人們在自由意志之下同意遵守的法律、機構的規定等義務，應凌 駕於個人的信仰、價值與原則  ⑤當個人基本福祉的權利與法律、規定及民間組織中的規則相衝 突時，個人基本福祉的權利不可優先考量  ⑥防止傷害的義務，提升公共利益的義務，這兩種義 務優先於個人財產所有權", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03318', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '規範倫理學（normativeethics）有關義務論（deontologicaltheories）與目的論（teleologicaltheories） 的敘述，下列何者正確？', '["對於相信目的論的社會工作者而言，實務上面臨倫理兩難的抉擇時，應該先衡量潛在的行為 結果", "目的論者主張，某些行為無論其結果如何，都有其本有的對或錯、好或壞之分", "義務論者主張，任何行為的對或錯，要視其所帶來的結果而定", "對於相信義務論的社會工作者而言，可以為了達到某種目的而不擇手段，即使違反某一重要的 法律"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03319', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '根據聯合國國際減災策略對於災難的定義，臺灣的夏季颱風不符合下列何種特性？', '["突發性", "造成嚴重傷害", "難精準推測", "低度地區性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "e1c1125ae3d4", "answer_pdf_sha1": "75f75026c11f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
